import{_ as a,c as i,o as t,ak as r,aq as s,an as n,al as o}from"./chunks/framework.DHLlVITf.js";const v=JSON.parse('{"title":"AireVault","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/airevault.md","filePath":"user-guide/airevault.md","lastUpdated":1784881015000}'),l={name:"user-guide/airevault.md"};function d(c,e,h,g,p,u){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="airevault" tabindex="-1">AireVault <a class="header-anchor" href="#airevault" aria-label="Permalink to “AireVault”">​</a></h1><p>Manage the variables and secrets used by your Aire Innovate products from a single, encrypted store.</p><p>The AireVault page is divided into two tabs: <strong>Variables</strong> and <strong>Secrets</strong>.</p><p>Variables and secrets created here can be referenced by:</p><ul class="icon-list"><li><img src="'+s+'" width="30" height="30" class="icon-img"> AireFrame</li><li><img src="'+n+'" width="30" height="30" class="icon-img"> AireFlow</li><li><img src="'+o+'" width="30" height="30" class="icon-img"> AireAssert</li></ul><h2 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to “Variables”">​</a></h2><p>Variables store configuration values that are visible in the UI, such as URLs, feature flags, or other non-sensitive settings.</p><p>The table displays:</p><ul><li><strong>Key</strong> – The unique identifier for the variable</li><li><strong>Default Value</strong> – The value used when no scope-specific override applies</li><li><strong>Scopes</strong> – The number of scoped overrides defined, if any</li></ul><p>Click the expand arrow on a row to view all scoped values for that variable.</p><h3 id="creating-and-editing-variables" tabindex="-1">Creating and Editing Variables <a class="header-anchor" href="#creating-and-editing-variables" aria-label="Permalink to “Creating and Editing Variables”">​</a></h3><p>Click <strong>Create</strong> to add a new variable, or use the edit action on an existing row to update its values.</p><p>Each variable has a <strong>key</strong> and one or more <strong>scoped values</strong>:</p><ul><li>Leave the <strong>Scope</strong> field blank to set the <strong>default value</strong>, used whenever no more specific scope matches</li><li>Add named scopes to override the value for specific contexts (for example, a particular environment or client)</li></ul><p>You can add additional scopes with <strong>Add scope</strong>, or remove one with the delete icon. At least one value is required.</p><h3 id="searching-and-sorting" tabindex="-1">Searching and Sorting <a class="header-anchor" href="#searching-and-sorting" aria-label="Permalink to “Searching and Sorting”">​</a></h3><p>Use the search bar to filter variables by key, scope, or value. Click the <strong>Key</strong> column header to toggle sorting alphabetically.</p><h3 id="copying-values" tabindex="-1">Copying Values <a class="header-anchor" href="#copying-values" aria-label="Permalink to “Copying Values”">​</a></h3><p>Use the copy icon on a row to copy the variable&#39;s key, default value, or its full JSON representation to the clipboard.</p><h2 id="secrets" tabindex="-1">Secrets <a class="header-anchor" href="#secrets" aria-label="Permalink to “Secrets”">​</a></h2><p>Secrets store sensitive values, such as API keys or credentials. Secret values are never displayed in the table and are masked by default when entering or editing them.</p><p>The table displays:</p><ul><li><strong>Key</strong> – The unique identifier for the secret</li><li><strong>Scopes</strong> – The number of scoped overrides defined, if any</li></ul><h3 id="creating-and-editing-secrets" tabindex="-1">Creating and Editing Secrets <a class="header-anchor" href="#creating-and-editing-secrets" aria-label="Permalink to “Creating and Editing Secrets”">​</a></h3><p>Click <strong>Create</strong> to add a new secret, or use the edit action on an existing row to update its values. Secrets use the same scoped value model as variables:</p><ul><li>Leave the <strong>Scope</strong> field blank to set the <strong>default value</strong></li><li>Add named scopes to override the value for specific contexts</li></ul><p>Secret values are hidden by default. Use the visibility icon to reveal a value while editing, or the file import button to load it from a file.</p><h3 id="searching-and-sorting-1" tabindex="-1">Searching and Sorting <a class="header-anchor" href="#searching-and-sorting-1" aria-label="Permalink to “Searching and Sorting”">​</a></h3><p>Use the search bar to filter secrets by key. Click the <strong>Key</strong> column header to toggle sorting alphabetically.</p><h3 id="copying-keys" tabindex="-1">Copying Keys <a class="header-anchor" href="#copying-keys" aria-label="Permalink to “Copying Keys”">​</a></h3><p>Use the copy icon on a row to copy the secret&#39;s key to the clipboard.</p><h2 id="deleting-variables-and-secrets" tabindex="-1">Deleting Variables and Secrets <a class="header-anchor" href="#deleting-variables-and-secrets" aria-label="Permalink to “Deleting Variables and Secrets”">​</a></h2><p>Use the delete icon on a row to remove a variable or secret. You&#39;ll be asked to confirm, as this permanently deletes all of its scoped values and cannot be undone.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to “Permissions”">​</a></h2><p>Access to Variables and Secrets is controlled separately by permission. If you do not have permission to view a tab, you&#39;ll see an <strong>Access Denied</strong> message instead of the table. Create, edit, delete actions are only shown if you hold the relevant permission.</p>',35)])])}const f=a(l,[["render",d]]);export{v as __pageData,f as default};
